class Solution {
    public int getKth(int lo, int hi, int k) {
        int[] powers = new int[hi - lo + 1];
        for (int i = lo; i <= hi; i++) {
            powers[i - lo] = calculatePower(i);
        }
        int[] sortedIndices = sortIndicesByPower(powers);
        return lo + sortedIndices[k - 1];
    }
    private int calculatePower(int x) {
        int count = 0;
        while (x != 1) {
            if (x % 2 == 0) {
                x /= 2;
            } else {
                x = 3 * x + 1;
            }
            count++;
        }
        return count;
    }
    private int[] sortIndicesByPower(int[] powers) {
        int[] indices = new int[powers.length];
        for (int i = 0; i < powers.length; i++) {
            indices[i] = i;
        }
        Arrays.sort(indices, (i, j) -> powers[i] - powers[j]);
        return indices;
    }
}
